}

//编辑
function editRow(row: Task_result_Class) {
  GetOne(row.id, itemName).then((res) => {
    task_result_FormRef.value?.open('edit', res, [task01_base_options.value]);
  });
}

//删除
function delRow(row: Task_result_Class) {
  Delete([row.id], itemName).then((res) => {
    executeRes(res, translate, () => {
      initData();
    });
  });
}
//翻页
function pageChange(page: number) {
  queryInfo.value.page = page;
  initData();
}
//改变页码
function pageSizeChange(pageSize: number) {
  queryInfo.value.page = 1;
  queryInfo.value.pageSize = pageSize;
  initData();
}

